%[text] # 离线处理数据
clear
clc
addpath('lib');
%%
%[text] ## 参数
% 读取配置文件
env = loadenv('.env');
data_dir = char(env("DATA_DIR"));
config_file = fopen([data_dir, '\config.json']);
if config_file == -1
    error("配置文件不存在！");
else
    config = jsondecode(fscanf(config_file, "%s"));
    fclose(config_file);
end

fs = config.fs;                     % 采样率
center_freq = config.center_freq;   % 载波中心频率
tag = config.tag(1 : 1);            % 标签频移参考频率
tag_num = length(tag);              % 标签数量
threshold = 2e3;                    % 标签频移频率的误差范围
fft_n = 1e5;                        % 傅里叶变换长度

every_window_flag = true;           % 是否逐窗口寻找标签频率（持续跟踪消除傅里叶变换跳变算法）

% 标签运动信息参考范围
motion_freq_ref = [1.0 0.5];
motion_freq_begin = motion_freq_ref - 0.5;
motion_freq_end = motion_freq_ref + 0.5;
motion_freq_n = 1e4;
%%
%[text] ## 信号
T = config.T;
BW = config.BW;
if isfield(config, 'f0')
    f0 = config.f0;  % 请勿必记住这里是频率平移的意思
else
    f0 = -BW / 2;
end
f0 = f0 + 0;
k = BW / T;
t = 0 : 1 / fs : T - 1 / fs;
up_chirp = chirp(t, f0, T, f0 + BW, "complex");
down_chirp = conj(up_chirp);
write_complex_binary(up_chirp, [data_dir '\chirp.cf32']);
%%
%[text] ## 数据
data = read_complex_binary([data_dir '\data1.cf32']);
if data == 0
    error("文件不存在！")
end
data_clip_factor = 0.05;
data = data(floor(data_clip_factor * length(data) : (1 - data_clip_factor) * length(data))).';
%%
%[text] ## Chirp起点
pre = data(1 : min(length(data), floor(100 * T * fs)));
[corr_res, ~] = xcorr(pre, up_chirp);
corr_res = abs(corr_res(length(pre) + 1 : length(corr_res)));
[~, chirp_starts] = findpeaks(corr_res, "MinPeakDistance", (T / 2) * fs);
%%
%[text] ## 窗口处理
% 窗口划分（对齐）
window_size = length(up_chirp);
window_begin = chirp_starts(floor(length(chirp_starts) / 2)) + 1;
window_end = length(data);
n_chirp_window = floor((window_end - window_begin + 1) / length(up_chirp));
window_end = window_begin + n_chirp_window * length(up_chirp) - 1;
n_window = n_chirp_window * length(up_chirp) / window_size;

window_t = window_size * 1 / fs;
processed_data = data(window_begin : window_end);

% Remove DC offset
if isfield(config, "dc_offset") && config.dc_offset
    dc_offset = mean(processed_data);
    processed_data = processed_data - dc_offset;
end

% 共轭解调
processed_data = conjugate_demodulate(processed_data, BW, T, fs);
%%
%[text] ## 求解相位
up_freq = zeros(tag_num, 1);
down_freq = zeros(tag_num, 1);
up_idx = zeros(tag_num, 1);
down_idx = zeros(tag_num, 1);

freqs = zeros(1, n_window);
up_freqs = zeros(tag_num, n_window);
down_freqs = zeros(tag_num, n_window);
hs = zeros(1, n_window);
up_hs = zeros(tag_num, n_window);
down_hs = zeros(tag_num, n_window);

% 初步确认激励信号与反向散射信号位置
[fft_f, fft_res] = compute_fft(processed_data, fs, fft_n);
figure %[output:1515f974]
plot(fft_f, abs(fft_res)) %[output:1515f974]

[pk, ~] = max(abs(fft_res));
[~, locs] = findpeaks(abs(fft_res), "MinPeakHeight", 0.5 * pk);
baseband_freqs = fft_f(locs);
[~, idx] = min(abs(baseband_freqs - 0));
baseband_freq = baseband_freqs(idx);
for j = 1 : tag_num
    [up_freq(j), down_freq(j), ~, ~, up_idx(j), down_idx(j)] = get_up_down(fft_res, fs, tag(j), threshold, baseband_freq);
end

for i = 1 : n_window
    window_data = processed_data((i - 1) * window_size + 1 : i * window_size);
    % 加窗函数
    window_data = window_function(window_data);
    [fft_f, fft_res] = compute_fft(window_data, fs, fft_n);
    if every_window_flag
        [pk, ~] = max(abs(fft_res));
        [~, locs] = findpeaks(abs(fft_res), "MinPeakHeight", 0.5 * pk);
        baseband_freqs = fft_f(locs);
        [~, idx] = min(abs(baseband_freqs - 0));
        idx = locs(idx);
        baseband_freq = fft_f(idx);
        for j = 1 : tag_num
            [~, ~, ~, ~, up_idx(j), down_idx(j)] = get_up_down(fft_res, fs, tag(j), threshold, baseband_freq);
        end
    end
    % 提取信号
    freqs(i) = fft_f(idx);
    hs(i) = fft_res(idx);
    up_freqs(:, i) = fft_f(up_idx);
    down_freqs(:, i) = fft_f(down_idx);
    up_hs(:, i) = fft_res(up_idx);
    down_hs(:, i) = fft_res(down_idx);
end

% 修正
if every_window_flag
    % 持续跟踪消除傅里叶变换跳变算法
    for i = 2 : n_window
        hs(i) = hs(i) .* exp(1j * pi * (freqs(i) - freqs(1)) * window_t);
        up_hs(:, i) = up_hs(:, i) .* exp(1j * pi * (up_freqs(:, i) - up_freqs(:, 1)) * window_t);
        down_hs(:, i) = down_hs(:, i) .* exp(1j * pi * (down_freqs(:, i) - down_freqs(:, 1)) * window_t);
    end
end
%%
%[text] ## 信号处理
for j = 1 : tag_num %[output:group:0c42fb54]
    disp('--------------------------------------------------------') %[output:81607288]
    disp(['Tag: ', num2str(tag(j))]) %[output:5f108e69]

    %% 信号处理

    % 收发端偏移消除
    [up_hs_div, down_hs_div] = syn_transceivers(hs, up_hs(j, :), down_hs(j, :));
    % 节点频率漂移消除 + 持续跟踪消歧义算法
    up_down_sqrt_hs = up_down_sqrt(up_hs_div, down_hs_div);
    
    % 时间戳
    time = 0 : window_t : (length(up_down_sqrt_hs) - 1) * window_t;

    %% 相位
    phase = unwrap(angle(up_down_sqrt_hs));
    phase = remove_outlier(phase);
    lambda = 3e8 / center_freq * 1000; % 单位（mm）
    phase = phase ./ (2 * pi) * lambda / 2;
    % phase = normalize(phase, "range", [-1, 1]);

    figure %[output:9d6fc6e8]
    plot(time, phase, "LineWidth", 1.5) %[output:9d6fc6e8]
    set(gca, "LineWidth", 1.5);
    grid on
    xlabel("时间（s）")
    ylabel("相位（normalized）")

    [freq, amp, ~, ~] = get_motion_information(phase, window_t, motion_freq_begin(j), motion_freq_end(j));
    disp(['原始频率：' num2str(freq) 'Hz']) %[output:37fbee10]

    % 巴特沃斯滤波器
    Wp = motion_freq_ref(j) * [0.625 1.5];
    Ws = motion_freq_ref(j) * [0.5, 1.8];
    Wp = Wp * window_t * 2;
    Ws = Ws * window_t * 2;
    Rp = 3;
    Rs = 5;
    [n, Wn] = buttord(Wp, Ws, Rp, Rs);
    [b,a] = butter(n, Wn);
    filtered_phase = filter(b, a, phase(1, :));

    figure %[output:6052f8e8]
    plot(time, filtered_phase, "LineWidth", 1.5) %[output:6052f8e8]
    set(gca, "LineWidth", 1.5);
    grid on
    xlabel("时间（s）")
    ylabel("滤波相位（normalized）")

    [freq, ~, ~, ~] = get_motion_information(filtered_phase, window_t, motion_freq_begin(j), motion_freq_end(j));
    disp(['频率：' num2str(freq) 'Hz']) %[output:2fc764ab]

    %% 幅度
    amplitude = abs(up_down_sqrt_hs);
    amplitude = remove_outlier(amplitude);
    amplitude = normalize(amplitude, "range", [-1, 1]);

    figure %[output:30b10715]
    plot(time, amplitude, "LineWidth", 1.5) %[output:30b10715]
    set(gca, "LineWidth", 1.5);
    grid on
    xlabel("时间（s）")
    ylabel("幅度（normalized）")

    [freq, ~, ~, ~] = get_motion_information(amplitude, window_t, motion_freq_begin(j), motion_freq_end(j));
    disp(['原始频率：' num2str(freq) 'Hz']) %[output:0b7dd92e]

    % 巴特沃斯滤波器
    filtered_amplitude = filter(b, a, amplitude(1, :));

    figure %[output:7726e73a]
    plot(time, filtered_amplitude, "LineWidth", 1.5) %[output:7726e73a]
    set(gca, "LineWidth", 1.5);
    grid on
    xlabel("时间（s）")
    ylabel("滤波幅度（normalized）")

    [freq, ~, ~, ~] = get_motion_information(filtered_amplitude, window_t, motion_freq_begin(j), motion_freq_end(j));
    disp(['频率：' num2str(freq) 'Hz']) %[output:1ee00c13]

    % 联合估计算法
    [f_range, loss] = joint_estimate(phase, amplitude, time, ...
        motion_freq_begin(j), motion_freq_end(j), motion_freq_n, 1, 1);

    figure %[output:1bad3443]
    plot(f_range, loss) %[output:1bad3443]
    [~, idx] = min(loss);

    freq = f_range(idx);
    disp(['频率：' num2str(freq) 'Hz']) %[output:65477675]
    
    [f_range, loss] = joint_estimate(filtered_phase, filtered_amplitude, time, ...
        motion_freq_begin(j), motion_freq_end(j), motion_freq_n, 1, 1);

    figure %[output:62805260]
    plot(f_range, loss) %[output:62805260]
    [~, idx] = min(loss);

    freq = f_range(idx);
    disp(['频率：' num2str(freq) 'Hz']) %[output:8370c6ed]
end %[output:group:0c42fb54]

